import React, { useState, useEffect } from 'react';
import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';
import { authAPI } from '../services/api';
import { swarmAPI } from '../services/swarmApi';
import { Badge } from '../components/ui';
import { Database, Leaf, Zap, ChevronDown, ChevronUp } from 'lucide-react';
import './ChatQueryPage.css';

const CHART_COLORS = ['#6366f1','#22c55e','#f59e0b','#14b8a6','#a855f7','#ef4444','#f97316','#06b6d4'];
const CARD_COLORS  = ['#6366f1','#22c55e','#f59e0b','#14b8a6'];

const SAMPLE_QUESTIONS = [
  'Give me a full business analysis of orders and customers',
  'Analyze revenue trends and top performing segments',
  'Show customer behavior patterns and order statistics',
  'Compare performance across all dimensions of the data',
];

const DB_TYPES = [
  { id: 'postgresql', label: 'PostgreSQL', icon: <Database size={13}/>, color: '#3b82f6' },
  { id: 'mysql',      label: 'MySQL',      icon: <Database size={13}/>, color: '#f59e0b' },
  { id: 'mongodb',    label: 'MongoDB',    icon: <Leaf size={13}/>,     color: '#22c55e' },
];

/* ── Smart chart selector ────────────────────────────────── */
function SmartChart({ data, height = 200 }) {
  if (!data?.length) return null;

  const allCols  = Object.keys(data[0]);
  const numCols  = allCols.filter(k => typeof data[0][k] === 'number');
  const textCols = allCols.filter(k => typeof data[0][k] !== 'number');

  if (!numCols.length) return null;

  const xCol   = textCols[0] || allCols[0];
  const yCol   = numCols[0];
  const isTime = xCol?.toLowerCase().includes('date') ||
                 xCol?.toLowerCase().includes('time') ||
                 xCol?.toLowerCase().includes('month');

  // Pie for small categorical data (2-6 rows, 1 numeric col)
  if (data.length <= 6 && numCols.length === 1 && textCols.length === 1 && !isTime) {
    return (
      <ResponsiveContainer width="100%" height={height}>
        <PieChart>
          <Pie data={data} dataKey={yCol} nameKey={xCol}
            cx="50%" cy="50%" outerRadius={height * 0.38} innerRadius={height * 0.15}
            paddingAngle={3}
            label={({name, percent}) => percent > 0.05 ? `${(percent*100).toFixed(0)}%` : ''}
            labelLine={false}>
            {data.map((_, i) => (
              <Cell key={i} fill={CHART_COLORS[i % CHART_COLORS.length]} stroke="white" strokeWidth={2}/>
            ))}
          </Pie>
          <Tooltip formatter={v => [Number(v).toLocaleString()]}
            contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}/>
          <Legend wrapperStyle={{fontSize:11}}/>
        </PieChart>
      </ResponsiveContainer>
    );
  }

  // Line for time series
  if (isTime) {
    return (
      <ResponsiveContainer width="100%" height={height}>
        <LineChart data={data} margin={{top:5, right:10, left:0, bottom:5}}>
          <defs>
            {numCols.slice(0,2).map((k,i) => (
              <linearGradient key={k} id={`lineArea${i}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%"  stopColor={CHART_COLORS[i]} stopOpacity={0.2}/>
                <stop offset="95%" stopColor={CHART_COLORS[i]} stopOpacity={0}/>
              </linearGradient>
            ))}
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#f1f3f7"/>
          <XAxis dataKey={xCol} tick={{fontSize:10, fill:'#6b7591'}} tickLine={false}
            axisLine={{stroke:'#e5e7eb'}}/>
          <YAxis tick={{fontSize:10, fill:'#6b7591'}} axisLine={false} tickLine={false}
            tickFormatter={v => Number(v).toLocaleString()}/>
          <Tooltip formatter={v => [Number(v).toLocaleString()]}
            contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}/>
          <Legend wrapperStyle={{fontSize:11}}/>
          {numCols.slice(0,2).map((k,i) => (
            <Line key={k} type="monotone" dataKey={k} stroke={CHART_COLORS[i]}
              strokeWidth={2.5} dot={{r:3, fill:CHART_COLORS[i]}} activeDot={{r:5}}/>
          ))}
        </LineChart>
      </ResponsiveContainer>
    );
  }

  // Bar chart default
  return (
    <ResponsiveContainer width="100%" height={height}>
      <BarChart data={data} margin={{top:5, right:10, left:0, bottom:5}}>
        <defs>
          {numCols.slice(0,2).map((k,i) => (
            <linearGradient key={k} id={`swarmBarGrad${i}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%"   stopColor={CHART_COLORS[i]} stopOpacity={0.9}/>
              <stop offset="100%" stopColor={CHART_COLORS[i]} stopOpacity={0.5}/>
            </linearGradient>
          ))}
        </defs>
        <CartesianGrid strokeDasharray="3 3" stroke="#f1f3f7" vertical={false}/>
        <XAxis dataKey={xCol} tick={{fontSize:10, fill:'#6b7591'}} tickLine={false}
          axisLine={{stroke:'#e5e7eb'}}/>
        <YAxis tick={{fontSize:10, fill:'#6b7591'}} axisLine={false} tickLine={false}
          tickFormatter={v => Number(v).toLocaleString()}/>
        <Tooltip formatter={v => [Number(v).toLocaleString()]}
          contentStyle={{borderRadius:8, border:'1px solid #e5e7eb', boxShadow:'0 4px 12px rgba(0,0,0,0.08)'}}/>
        <Legend wrapperStyle={{fontSize:11}}/>
        {numCols.slice(0,2).map((k,i) => (
          <Bar key={k} dataKey={k} fill={`url(#swarmBarGrad${i})`}
            radius={[6,6,0,0]} maxBarSize={52}/>
        ))}
      </BarChart>
    </ResponsiveContainer>
  );
}

/* ── Summary KPI cards ───────────────────────────────────── */
function SummaryKpis({ subtaskResults }) {
  // Extract numeric highlights from all results
  const kpis = [];
  subtaskResults.forEach((r, idx) => {
    if (r.error || !r.data?.length) return;
    const numCols = r.columns.filter(c => typeof r.data[0][c] === 'number');
    numCols.slice(0, 1).forEach(col => {
      const vals  = r.data.map(row => Number(row[col])).filter(v => !isNaN(v));
      const total = vals.reduce((a,b) => a+b, 0);
      const max   = Math.max(...vals);
      kpis.push({
        label: col.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
        total: total,
        max:   max,
        count: r.count,
        color: CARD_COLORS[idx % CARD_COLORS.length],
      });
    });
  });

  if (!kpis.length) return null;

  return (
    <div style={{
      display: 'grid',
      gridTemplateColumns: `repeat(${Math.min(kpis.length, 4)}, 1fr)`,
      gap: 10, marginBottom: 4,
    }}>
      {kpis.map((kpi, i) => (
        <div key={i} style={{
          background: `${kpi.color}10`,
          border: `1.5px solid ${kpi.color}25`,
          borderRadius: 10, padding: '12px 14px',
          transition: 'transform 0.2s',
        }}
          onMouseEnter={e => e.currentTarget.style.transform = 'translateY(-2px)'}
          onMouseLeave={e => e.currentTarget.style.transform = 'translateY(0)'}
        >
          <div style={{fontSize:10, color:'#6b7591', fontWeight:600,
            textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:6}}>
            {kpi.label}
          </div>
          <div style={{fontSize:22, fontWeight:800, color:kpi.color, lineHeight:1}}>
            {Number(kpi.total).toLocaleString(undefined, {maximumFractionDigits:1})}
          </div>
          <div style={{fontSize:10, color:'#9ca3af', marginTop:4}}>
            Total · Max: {Number(kpi.max).toLocaleString(undefined, {maximumFractionDigits:1})}
          </div>
        </div>
      ))}
    </div>
  );
}

/* ── Combined chart view ─────────────────────────────────── */
function CombinedCharts({ subtaskResults }) {
  const validResults = subtaskResults.filter(r => !r.error && r.data?.length > 0);
  if (!validResults.length) return null;

  return (
    <div>
      <div style={{fontSize:11, fontWeight:700, color:'#374151',
        textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:10}}>
        📊 Visual Overview
      </div>
      <div style={{
        display: 'grid',
        gridTemplateColumns: validResults.length === 1 ? '1fr' :
                             validResults.length === 2 ? '1fr 1fr' : '1fr 1fr 1fr',
        gap: 12,
      }}>
        {validResults.map((r, i) => {
          const color = CARD_COLORS[i % CARD_COLORS.length];
          const numCols = r.columns.filter(c => typeof r.data[0]?.[c] === 'number');
          if (!numCols.length) return null;

          return (
            <div key={i} style={{
              background: '#fff',
              border: `1.5px solid ${color}25`,
              borderRadius: 12,
              padding: '14px 14px 10px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.04)',
            }}>
              <div style={{
                display:'flex', alignItems:'center', gap:8, marginBottom:12,
              }}>
                <div style={{
                  width:24, height:24, borderRadius:'50%', background:color,
                  color:'#fff', fontSize:11, fontWeight:700,
                  display:'flex', alignItems:'center', justifyContent:'center',
                }}>
                  {i + 1}
                </div>
                <div style={{fontSize:11, fontWeight:600, color:'#374151',
                  overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap',
                  flex:1}}>
                  {r.question}
                </div>
                <span style={{
                  fontSize:10, color:color, background:`${color}15`,
                  borderRadius:5, padding:'2px 6px', flexShrink:0,
                }}>
                  {r.count} rows
                </span>
              </div>
              <SmartChart data={r.data} height={180}/>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ── Summary card ────────────────────────────────────────── */
function SummaryCard({ summary }) {
  if (!summary) return null;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
      {summary.headline && (
        <div style={{
          background: 'linear-gradient(135deg, #eef2ff, #f5f3ff)',
          border: '1.5px solid #e0e7ff', borderRadius: 12,
          padding: '16px 20px', display: 'flex', alignItems: 'flex-start', gap: 12,
        }}>
          <div style={{
            width:36, height:36, borderRadius:'50%', background:'#6366f1',
            display:'flex', alignItems:'center', justifyContent:'center',
            fontSize:18, flexShrink:0,
          }}>💡</div>
          <div>
            <div style={{fontSize:10, fontWeight:700, color:'#6366f1',
              textTransform:'uppercase', letterSpacing:'0.08em', marginBottom:4}}>
              Swarm Intelligence Summary
            </div>
            <div style={{fontSize:13, color:'#374151', lineHeight:1.7, fontWeight:500}}>
              {summary.headline}
            </div>
          </div>
        </div>
      )}

      {summary.executive_summary && (
        <div style={{background:'#fff', border:'1.5px solid #e5e7eb',
          borderRadius:12, padding:'16px 18px'}}>
          <div style={{fontSize:11, fontWeight:700, color:'#374151',
            textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:10}}>
            📋 Executive Summary
          </div>
          <div style={{fontSize:13, color:'#374151', lineHeight:1.7}}>
            {summary.executive_summary}
          </div>
        </div>
      )}

      <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:12}}>
        {Array.isArray(summary.key_insights) && summary.key_insights.length > 0 && (
          <div style={{background:'#fff', border:'1.5px solid #e5e7eb',
            borderRadius:12, padding:'16px 18px'}}>
            <div style={{fontSize:11, fontWeight:700, color:'#374151',
              textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:10}}>
              🔍 Key Insights
            </div>
            {summary.key_insights.map((insight, i) => (
              <div key={i} style={{display:'flex', alignItems:'flex-start',
                gap:10, marginBottom:10}}>
                <span style={{
                  minWidth:22, height:22,
                  background:'linear-gradient(135deg,#6366f1,#8b5cf6)',
                  color:'#fff', borderRadius:6, fontSize:11, fontWeight:700,
                  display:'flex', alignItems:'center', justifyContent:'center',
                  flexShrink:0, marginTop:1,
                }}>{i+1}</span>
                <span style={{fontSize:12, color:'#374151', lineHeight:1.6}}>
                  {insight}
                </span>
              </div>
            ))}
          </div>
        )}

        {Array.isArray(summary.recommendations) && summary.recommendations.length > 0 && (
          <div style={{background:'linear-gradient(135deg,#f0fdf4,#ecfeff)',
            border:'1.5px solid #86efac', borderRadius:12, padding:'16px 18px'}}>
            <div style={{fontSize:11, fontWeight:700, color:'#16a34a',
              textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:10}}>
              ✨ Recommendations
            </div>
            {summary.recommendations.map((rec, i) => (
              <div key={i} style={{display:'flex', alignItems:'flex-start',
                gap:10, marginBottom:10}}>
                <span style={{
                  width:20, height:20, borderRadius:'50%',
                  background:'#f0fdf4', border:'1.5px solid #86efac',
                  color:'#16a34a', fontSize:12, fontWeight:700,
                  display:'flex', alignItems:'center', justifyContent:'center',
                  flexShrink:0, marginTop:1,
                }}>→</span>
                <span style={{fontSize:12, color:'#374151', lineHeight:1.6}}>
                  {rec}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/* ── Subtask card with chart ─────────────────────────────── */
function SubtaskCard({ result, index }) {
  const [expanded, setExpanded] = useState(false);
  const isError = !!result.error;
  const color   = CARD_COLORS[index % CARD_COLORS.length];
  const hasChart = !isError && result.data?.length > 0 &&
    result.columns.some(c => typeof result.data[0]?.[c] === 'number');

  return (
    <div style={{
      background:'#fff', border:`1.5px solid ${color}25`,
      borderRadius:12, overflow:'hidden',
      boxShadow:'0 1px 4px rgba(0,0,0,0.04)',
    }}>
      {/* Header */}
      <div style={{
        background:`${color}10`, borderBottom:`1px solid ${color}20`,
        padding:'12px 16px', display:'flex', alignItems:'center', gap:10,
        cursor:'pointer',
      }} onClick={() => setExpanded(e => !e)}>
        <div style={{
          width:28, height:28, borderRadius:'50%', background:color,
          color:'#fff', fontSize:12, fontWeight:700,
          display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0,
        }}>
          {index+1}
        </div>
        <div style={{flex:1}}>
          <div style={{fontSize:12, fontWeight:600, color:'#111827'}}>
            {result.question}
          </div>
          <div style={{fontSize:11, color:'#6b7280', marginTop:2}}>
            {isError ? '✗ Failed' : `✓ ${result.count} rows · ${result.execution_time_ms}ms`}
          </div>
        </div>
        <div style={{display:'flex', alignItems:'center', gap:8}}>
          {result.react_trace?.attempts > 1 && (
            <span style={{fontSize:10, color:'#d97706', background:'#fffbeb',
              border:'1px solid #fcd34d', borderRadius:5, padding:'2px 6px'}}>
              🔄 {result.react_trace.attempts} attempts
            </span>
          )}
          {hasChart && !expanded && (
            <span style={{fontSize:10, color:color, background:`${color}15`,
              borderRadius:5, padding:'2px 6px'}}>
              📊 Chart
            </span>
          )}
          {expanded
            ? <ChevronUp size={14} color="#6b7280"/>
            : <ChevronDown size={14} color="#6b7280"/>}
        </div>
      </div>

      {/* Always show mini chart when not expanded */}
      {!expanded && hasChart && (
        <div style={{padding:'12px 16px 10px'}}>
          <SmartChart data={result.data} height={160}/>
        </div>
      )}

      {/* Expanded — show chart + SQL + table */}
      {expanded && (
        <div style={{padding:'12px 16px'}}>
          {isError ? (
            <div style={{color:'#dc2626', fontSize:12, background:'#fef2f2',
              padding:'8px 12px', borderRadius:8}}>
              {result.error}
            </div>
          ) : (
            <>
              {/* Chart */}
              {hasChart && (
                <div style={{marginBottom:14}}>
                  <SmartChart data={result.data} height={200}/>
                </div>
              )}

              {/* SQL */}
              {result.sql && (
                <div style={{marginBottom:12}}>
                  <div style={{fontSize:10, fontWeight:700, color:'#6b7280',
                    textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:6}}>
                    Generated Query
                  </div>
                  <pre style={{
                    fontSize:11, background:'#f8fafc', border:'1px solid #e2e8f0',
                    borderRadius:8, padding:'8px 12px', overflow:'auto',
                    whiteSpace:'pre-wrap', wordBreak:'break-word', margin:0,
                    fontFamily:'monospace', color:'#1e1b4b',
                  }}>
                    {result.sql}
                  </pre>
                </div>
              )}

              {/* Data table */}
              {result.data?.length > 0 && (
                <div style={{overflowX:'auto', borderRadius:8, border:'1px solid #e5e7eb'}}>
                  <table style={{width:'100%', borderCollapse:'collapse', fontSize:'0.8rem'}}>
                    <thead>
                      <tr>
                        {result.columns.map(c => (
                          <th key={c} style={{padding:'7px 12px', textAlign:'left',
                            fontWeight:600, color:'#374151',
                            borderBottom:'1.5px solid #e5e7eb',
                            background:'#f9fafb', whiteSpace:'nowrap'}}>
                            {c}
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {result.data.map((row, i) => (
                        <tr key={i} style={{background: i%2===0?'white':'#fafafa'}}>
                          {result.columns.map(c => (
                            <td key={c} style={{padding:'7px 12px',
                              borderBottom:'1px solid #f3f4f6', color:'#374151'}}>
                              {row[c]==null
                                ? <span style={{color:'#d1d5db'}}>null</span>
                                : typeof row[c]==='number'
                                  ? <strong>{Number(row[c]).toLocaleString()}</strong>
                                  : String(row[c])}
                            </td>
                          ))}
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </>
          )}
        </div>
      )}
    </div>
  );
}

/* ── Main SwarmPage ──────────────────────────────────────── */
export default function SwarmPage() {
  const [dbType, setDbType]             = useState('postgresql');
  const [connections, setConnections]   = useState([]);
  const [selectedConn, setSelectedConn] = useState('');
  const [question, setQuestion]         = useState('');
  const [maxSubtasks, setMaxSubtasks]   = useState(3);
  const [loading, setLoading]           = useState(false);
  const [result, setResult]             = useState(null);
  const [error, setError]               = useState('');

  const [mongoCollections, setMongoCollections]         = useState([]);
  const [selectedCollections, setSelectedCollections]   = useState([]);

  useEffect(() => {
    authAPI.connections().then(r => {
      const filtered = (r.data||[]).filter(c => c.db_type === dbType);
      setConnections(filtered);
      setSelectedConn(filtered.length ? String(filtered[0].id) : '');
      setResult(null); setError('');
      setMongoCollections([]); setSelectedCollections([]);
    }).catch(() => {});
  }, [dbType]);

  const conn = connections.find(c => String(c.id) === String(selectedConn));

  useEffect(() => {
    if (dbType !== 'mongodb' || !conn) return;
    setMongoCollections([]); setSelectedCollections([]);
    authAPI.getPassword(conn.id).then(r => {
      const uri = r.data?.password;
      if (!uri) return;
      const base  = process.env.REACT_APP_API_URL || 'http://localhost:8000';
      const token = localStorage.getItem('token');
      fetch(`${base}/mongo/collections?mongo_uri=${encodeURIComponent(uri)}&db_name=${conn.dbname}`, {
        headers: { Authorization: `Bearer ${token}` }
      })
        .then(res => res.json())
        .then(data => {
          const colls = data.collections || [];
          setMongoCollections(colls);
          setSelectedCollections(colls.slice(0, 2));
        }).catch(() => {});
    }).catch(() => {});
  }, [selectedConn, dbType]);

  const run = async () => {
    if (!question.trim() || !conn) return;
    setLoading(true); setError(''); setResult(null);
    try {
      let res;
      if (dbType === 'postgresql') {
        const uriRes = await authAPI.getUri(conn.id);
        const pg_uri = uriRes.data?.uri;
        if (!pg_uri) throw new Error('Could not get connection URI');
        res = await swarmAPI.pgQuery({ pg_uri, question: question.trim(), limit:50, max_subtasks:maxSubtasks });

      } else if (dbType === 'mysql') {
        const pwRes  = await authAPI.getPassword(conn.id);
        const password = pwRes.data?.password || '';
        res = await swarmAPI.mysqlQuery({
          host: conn.host, port: conn.port,
          database: conn.dbname, username: conn.db_username, password,
          question: question.trim(), limit:50, max_subtasks:maxSubtasks,
        });

      } else if (dbType === 'mongodb') {
        const pwRes = await authAPI.getPassword(conn.id);
        const mongo_uri = pwRes.data?.password;
        if (!mongo_uri) throw new Error('Could not get connection URI');
        res = await swarmAPI.mongoQuery({
          mongo_uri, db_name: conn.dbname,
          collections: selectedCollections.length > 0 ? selectedCollections : mongoCollections.slice(0,2),
          question: question.trim(), limit:50, max_subtasks:maxSubtasks,
        });
      }
      setResult(res.data);
    } catch (e) {
      setError(e.response?.data?.detail || e.message || 'Swarm query failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="chat-query-page fade-in">

      {/* Left panel */}
      <div className="cqp-left">
        <div className="cqp-section">
          <div className="cqp-section-label">Database Type</div>
          <div style={{display:'flex', flexDirection:'column', gap:6}}>
            {DB_TYPES.map(db => (
              <button key={db.id} onClick={() => setDbType(db.id)}
                style={{
                  display:'flex', alignItems:'center', gap:8,
                  padding:'8px 12px', borderRadius:8, border:'1.5px solid',
                  fontSize:12, fontWeight:600, cursor:'pointer',
                  borderColor: dbType===db.id ? db.color : '#e5e7eb',
                  background:  dbType===db.id ? `${db.color}12` : '#fff',
                  color:       dbType===db.id ? db.color : '#6b7280',
                  transition:'all 0.15s',
                }}>
                {db.icon} {db.label}
              </button>
            ))}
          </div>
        </div>

        <div className="cqp-section">
          <div className="cqp-section-label">Connection</div>
          {connections.length === 0 ? (
            <div className="cqp-empty-note">
              No {dbType} connections.{' '}
              <a href="/connections" style={{color:'var(--accent)'}}>Add one</a>
            </div>
          ) : (
            <select className="cqp-select" value={selectedConn}
              onChange={e => setSelectedConn(e.target.value)}>
              {connections.map(c => (
                <option key={c.id} value={String(c.id)}>{c.name||c.dbname}</option>
              ))}
            </select>
          )}
        </div>

        {dbType === 'mongodb' && mongoCollections.length > 0 && (
          <div className="cqp-section">
            <div className="cqp-section-label">Collections</div>
            <div className="cqp-checklist">
              {mongoCollections.map(c => (
                <label key={c} className={`cqp-check-item ${selectedCollections.includes(c)?'on':''}`}>
                  <input type="checkbox" checked={selectedCollections.includes(c)}
                    onChange={() => setSelectedCollections(prev =>
                      prev.includes(c) ? prev.filter(x=>x!==c) : [...prev,c]
                    )}/>
                  <span>{c}</span>
                </label>
              ))}
            </div>
          </div>
        )}

        <div className="cqp-section">
          <div className="cqp-section-label">Parallel Agents</div>
          <div style={{display:'flex', gap:6}}>
            {[2,3,4].map(n => (
              <button key={n} onClick={() => setMaxSubtasks(n)}
                style={{
                  flex:1, padding:'6px 0', borderRadius:8, border:'1.5px solid',
                  fontSize:13, fontWeight:700, cursor:'pointer',
                  borderColor: maxSubtasks===n ? '#6366f1' : '#e5e7eb',
                  background:  maxSubtasks===n ? '#eef2ff' : '#fff',
                  color:       maxSubtasks===n ? '#6366f1' : '#6b7280',
                }}>
                {n}
              </button>
            ))}
          </div>
          <div style={{fontSize:11, color:'#9ca3af', marginTop:6}}>
            {maxSubtasks} agents will run simultaneously
          </div>
        </div>

        <div className="cqp-section cqp-suggestions">
          <div className="cqp-section-label"><Zap size={11}/> Sample questions</div>
          {SAMPLE_QUESTIONS.map(s => (
            <button key={s} className="cqp-suggestion" onClick={() => setQuestion(s)}>{s}</button>
          ))}
        </div>
      </div>

      {/* Right panel */}
      <div className="cqp-right">
        <div className="cqp-chat-header">
          <Zap size={15} color="#6366f1"/>
          <span>Swarm Agents</span>
          <div style={{marginLeft:'auto', display:'flex', alignItems:'center', gap:8}}>
            <span style={{
              fontSize:11, fontWeight:600, padding:'2px 8px', borderRadius:6,
              background: dbType==='postgresql'?'#dbeafe': dbType==='mysql'?'#fef3c7':'#dcfce7',
              color:      dbType==='postgresql'?'#1d4ed8': dbType==='mysql'?'#b45309':'#15803d',
            }}>
              {dbType.toUpperCase()}
            </span>
            <Badge color="blue">{conn?.name||'No connection'}</Badge>
          </div>
        </div>

        <div className="cqp-messages" style={{padding:'20px 24px'}}>
          {!result && !loading && !error && (
            <div className="cqp-welcome">
              <Zap size={28} color="#6366f1"/>
              <div className="cqp-welcome-title">Swarm Parallel Agents</div>
              <div className="cqp-welcome-sub">
                Ask a complex question — multiple agents run simultaneously and combine
                results into a unified visual report
              </div>
            </div>
          )}

          {loading && (
            <div style={{textAlign:'center', padding:'60px 20px'}}>
              <div style={{display:'flex', justifyContent:'center', gap:12, marginBottom:16}}>
                {Array.from({length:maxSubtasks}).map((_,i) => (
                  <div key={i} style={{
                    width:40, height:40, borderRadius:'50%',
                    background:['#6366f1','#22c55e','#f59e0b','#14b8a6'][i%4],
                    display:'flex', alignItems:'center', justifyContent:'center',
                    color:'#fff', fontWeight:700, fontSize:14,
                    animation:`bounce 1.2s ease-in-out ${i*0.2}s infinite`,
                  }}>
                    {i+1}
                  </div>
                ))}
              </div>
              <div style={{fontSize:14, fontWeight:600, color:'#374151'}}>
                {maxSubtasks} agents running in parallel on {dbType}...
              </div>
              <div style={{fontSize:12, color:'#9ca3af', marginTop:6}}>
                Planning subtasks → Executing queries → Generating summary
              </div>
            </div>
          )}

          {error && (
            <div style={{padding:'12px 16px', background:'#fef2f2',
              border:'1px solid #fecaca', borderRadius:10,
              color:'#dc2626', fontSize:13}}>
              ⚠️ {error}
            </div>
          )}

          {result && !loading && (
            <div style={{display:'flex', flexDirection:'column', gap:16}}>

              {/* Stats bar */}
              <div style={{
                display:'flex', gap:10, flexWrap:'wrap',
                padding:'12px 16px', background:'#f9fafb',
                borderRadius:10, border:'1px solid #f3f4f6',
              }}>
                {[
                  {label:'Agents run',  value:result.agents_run,       color:'#6366f1'},
                  {label:'Succeeded',   value:result.agents_succeeded,  color:'#16a34a'},
                  {label:'Total time',  value:`${(result.total_ms/1000).toFixed(1)}s`, color:'#0891b2'},
                  {label:'Subtasks',    value:result.subtasks?.length,  color:'#f59e0b'},
                ].map(s => (
                  <div key={s.label} style={{
                    background:'#fff', borderRadius:8, padding:'8px 14px',
                    border:`1.5px solid ${s.color}25`, textAlign:'center',
                  }}>
                    <div style={{fontSize:18, fontWeight:800, color:s.color}}>{s.value}</div>
                    <div style={{fontSize:10, color:'#6b7280'}}>{s.label}</div>
                  </div>
                ))}
              </div>

              {/* KPI cards */}
              <SummaryKpis subtaskResults={result.subtask_results}/>

              {/* Combined charts */}
              <CombinedCharts subtaskResults={result.subtask_results}/>

              {/* Summary */}
              <SummaryCard summary={result.summary}/>

              {/* Individual subtask cards with mini charts */}
              <div>
                <div style={{fontSize:11, fontWeight:700, color:'#374151',
                  textTransform:'uppercase', letterSpacing:'0.06em', marginBottom:10}}>
                  Individual Agent Results
                </div>
                <div style={{display:'flex', flexDirection:'column', gap:10}}>
                  {result.subtask_results.map((r,i) => (
                    <SubtaskCard key={i} result={r} index={i}/>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="cqp-input-bar">
          <textarea
            className="cqp-textarea"
            value={question}
            onChange={e => setQuestion(e.target.value)}
            onKeyDown={e => { if (e.key==='Enter'&&!e.shiftKey){e.preventDefault();run();} }}
            placeholder={`Ask a complex question about your ${dbType} data...`}
            rows={1}
            disabled={loading}
          />
          <button className="cqp-send-btn" onClick={run}
            disabled={loading||!question.trim()||!conn}>
            <Zap size={15}/>
          </button>
        </div>
      </div>

      <style>{`
        @keyframes bounce {
          0%,80%,100% { transform: translateY(0); }
          40% { transform: translateY(-10px); }
        }
      `}</style>
    </div>
  );
}
